interceptor.preaction:

Util u=new Util();
String ip=u.getRemoteIP(rrequest);
rrequest.getRequest().setAttribute("reqKey2", ip);

update.value:

           UPDATE IBS.T3_SIGN_PROD_PRICE 
           SET PRICE=@{PRICE}
               ,MODIFY_PEOPLE=#{user_id}
               ,MODIFY_TIME=#{current_time}
               ,MODIFY_IP=#{ip}
		   WHERE BRANCH_ORG_ID=@{BRANCH_ORG_ID} 
		   AND BONUS_TYPE_ID=@{BONUS_TYPE_ID}
	       AND CHANNLE_ID=@{CHANNLE_ID}
